#!/usr/bin/env python3

import os
import sys
import shutil
import subprocess
from pathlib import Path


ROOT = Path(__file__).resolve().parent
DIST_DIR = ROOT / "dist"
BUILD_DIR = ROOT / "build"
REQUIREMENTS = ROOT / "requirements.txt"


def run(cmd, cwd=ROOT):
    print(f"+ {' '.join(cmd)}", flush=True)
    subprocess.run(cmd, cwd=cwd, check=True)


def install_dependencies():
    if REQUIREMENTS.exists():
        run([sys.executable, "-m", "pip", "install", "--disable-pip-version-check", "-r", str(REQUIREMENTS)])
    else:
        print("requirements.txt not found, skipping dependency installation.", flush=True)


def run_tests():
    pytest_ini = ROOT / "pytest.ini"
    tests_dir = ROOT / "tests"
    if pytest_ini.exists() or tests_dir.exists():
        run([sys.executable, "-m", "pytest", "-q"])
    else:
        print("No tests detected, skipping test step.", flush=True)


def package_deployment():
    DIST_DIR.mkdir(exist_ok=True)
    BUILD_DIR.mkdir(exist_ok=True)

    archive_base = BUILD_DIR / "deployment_package"
    if (DIST_DIR / "deployment_package.zip").exists():
        (DIST_DIR / "deployment_package.zip").unlink()

    temp_dir = BUILD_DIR / "package_contents"
    if temp_dir.exists():
        shutil.rmtree(temp_dir)
    temp_dir.mkdir(parents=True)

    exclude = {
        ".git",
        ".github",
        ".venv",
        "venv",
        "__pycache__",
        "dist",
        "build",
        ".pytest_cache",
        ".mypy_cache",
        ".tox",
        ".idea",
        ".vscode",
    }

    for item in ROOT.iterdir():
        if item.name in exclude:
            continue
        target = temp_dir / item.name
        if item.is_dir():
            shutil.copytree(
                item,
                target,
                ignore=shutil.ignore_patterns(
                    "__pycache__",
                    "*.pyc",
                    "*.pyo",
                    ".DS_Store",
                    ".pytest_cache",
                    ".mypy_cache",
                    ".tox",
                ),
            )
        elif item.is_file():
            shutil.copy2(item, target)

    shutil.make_archive(str(archive_base), "zip", root_dir=temp_dir)
    shutil.move(str(archive_base) + ".zip", DIST_DIR / "deployment_package.zip")
    shutil.rmtree(temp_dir)

    print(f"Created package: {DIST_DIR / 'deployment_package.zip'}", flush=True)


def main():
    install_dependencies()
    run_tests()
    package_deployment()
    print("Deployment workflow completed successfully.", flush=True)


if __name__ == "__main__":
    try:
        main()
    except subprocess.CalledProcessError as e:
        print(f"Command failed with exit code {e.returncode}", file=sys.stderr, flush=True)
        sys.exit(e.returncode)
    except Exception as e:
        print(f"Deployment workflow failed: {e}", file=sys.stderr, flush=True)
        sys.exit(1)